import tensorflow as tfimport matplotlib.pyplot as pltmnist = tf.keras.datasets.mnist(train_x, train_y), (test_x, test_y) = mnist.load_data()x_train = train_x.reshape(60000, 784).astype('float32') / 255x_test = test_x.reshape(10000, 784).astype('float32') / 255print(x_train.shape)model = tf.keras.models.Sequential([    tf.keras.layers.Dense(128, activation='relu'),    tf.keras.layers.Dense(64, activation='relu'),    tf.keras.layers.Dense(32, activation='relu'),    tf.keras.layers.Dense(10, activation='softmax')])model.compile(optimizer='sgd',              loss='sparse_categorical_crossentropy',              metrics=['accuracy'])# save_weights_only=False 保存所有模型# save_weights_only=True 只保存权重文件cp_callback = tf.keras.callbacks.ModelCheckpoint(filepath='./model/',                                                 save_weights_only=True,                                                 save_best_only=True)model.fit(x_train,          train_y,          batch_size=64,          epochs=1,          validation_data=(x_test, test_y),          validation_freq=1,          callbacks=[cp_callback])model.summary()# 保存网络结构json_config = model.to_json()with open('./model/model_config.json', 'w') as json_file:    json_file.write(json_config)del model         # 删除原有网络结构'''加载模型结构和参数，识别测试集中的手写数字'''plt.imshow(test_x[1], cmap='gray')plt.show()# 加载全部模型# new_model = tf.keras.models.load_model('./model/')# 加载网络结构和权重with open('./model/model_config.json') as json_file:    json_config = json_file.read()new_model = tf.keras.models.model_from_json(json_config)new_model.load_weights('./model/')predict = new_model(x_test)[1]print(tf.argmax(predict))